  // Estados locais
  const [localNudges, setLocalNudges] = useState(nudgesData);
  const [usersWithIcons, setUsersWithIcons] = useState([]);
  const [sortBy, setSortBy] = useState('Recent');
  const [topTabActive, setTopTabActive] = useState('received');
